// SPDX-License-Identifier: UNLICENSED
pragma solidity ^0.8.20;

import "forge-std/Test.sol";
import "../src/Generated.sol";

contract GeneratedTest is Test {
    SimpleVault vault;
    address user = address(0xBEEF);

    function setUp() public {
        vault = new SimpleVault();
    }

    function testOwnerIsDeployer() public {
        assertEq(vault.owner(), address(this));
    }

    function testInitialValueIsZero() public {
        assertEq(vault.getValue(), 0);
    }

    function testOwnerCanSetValue() public {
        vault.setValue(42);
        assertEq(vault.getValue(), 42);
    }

    function testNonOwnerCannotSetValue() public {
        vm.prank(user);
        vm.expectRevert();
        vault.setValue(7);
    }
}
